const email = 'pentest@example.com';
const passwords = ['123456', 'password', 'admin', 'letmein', 'qwerty'];
// Enviamos 5 intentos de login fallidos secuencialmente
cy.wrap(passwords).each(pwd => {
  cy.request({
    method: 'POST',
    url: `${Cypress.env('API_BASE_URL')}/users/login`,
    body: {
      email,
      password: pwd
    },
    failOnStatusCode: false // No queremos que Cypress falle por el 401
  }).then(response => {
    // Esperamos un 401 Unauthorized
    expect(response.status).to.eq(401);
    // Verificamos que NO se nos bloquea con un 429 (Too Many Requests)
    expect(response.status).not.to.eq(429);
    cy.log(`Intento con contraseña "${pwd}" -> Status ${response.status}`);
  });
}).then(() => {
  cy.log(' VULNERABILIDAD DETECTADA: La API permite múltiples intentos de login fallidos sin bloqueo temporal.');
  cy.log(' (Nota de QA: Este test documenta un comportamiento existente y se recomienda implementar Rate Limiting.)');
});
